import React from "react";
import { Box, Typography, Button, Link } from "@mui/material";
import PhoneIcon from "@mui/icons-material/Phone";
import EmailIcon from "@mui/icons-material/Email";
import LinkedInIcon from "@mui/icons-material/LinkedIn";

const Contact = () => {
  return (
    <Box
      sx={{
        padding: "20px",
        backgroundColor: "#f5f5f5",
        borderRadius: "8px",
        boxShadow: 2,
        display: "flex",
        flexDirection: "column",
        alignItems: "flex-start",
      }}
    >
      <Typography variant="h5" sx={{ marginBottom: "15px", fontWeight: "bold" }}>
        Contact Information
      </Typography>
      <Box sx={{ display: "flex", alignItems: "center", marginBottom: "10px" }}>
        <PhoneIcon sx={{ marginRight: "10px" }} />
        <Typography variant="body1">+91 9438509060</Typography>
      </Box>
      <Box sx={{ display: "flex", alignItems: "center", marginBottom: "10px" }}>
        <EmailIcon sx={{ marginRight: "10px" }} />
        <Typography variant="body1">
          <Link href="mailto:soumya050794@gmail.com">soumya050794@gmail.com</Link>
        </Typography>
      </Box>
      <Box sx={{ display: "flex", alignItems: "center", marginBottom: "10px" }}>
        <LinkedInIcon sx={{ marginRight: "10px" }} />
        <Typography variant="body1">
          <Link
            href="https://www.linkedin.com/in/soumya-ranjan-nayak-50069a15a"
            target="_blank"
            rel="noopener"
          >
            LinkedIn: Soumya Ranjan Nayak
          </Link>
        </Typography>
      </Box>
      <Button
        variant="contained"
        sx={{
          backgroundColor: "#0077b5",
          color: "white",
          "&:hover": {
            backgroundColor: "#005f8c",
          },
        }}
        onClick={() => window.open("https://www.linkedin.com/in/soumya-ranjan-nayak-50069a15a")}
      >
        Visit LinkedIn Profile
      </Button>
    </Box>
  );
};

export default Contact;
